const incoming = $input.first().json ?? {};
const body = incoming.body ?? incoming ?? {};

const getString = (value) => typeof value === 'string' && value.trim() ? value.trim() : '';
const getArray = (value) => Array.isArray(value) ? value : [];
const getRecord = (value) => value && typeof value === 'object' && !Array.isArray(value) ? value : {};

const action = getString(body.action) === 'launch' ? 'launch' : 'prepare';
const callback = getRecord(body.callback);
const job = getRecord(body.job);
const target = getRecord(body.target);
const publishPackage = getRecord(body.publishPackage);

const channel = getString(body.channel) || getString(target.channel);
const title = getString(body.title) || getString(publishPackage.title) || getString(target.title);
const description = getString(body.description) || getString(target.description);
const caption = getString(body.caption) || getString(publishPackage.caption) || getString(publishPackage.descriptionWithHashtags) || description;
const firstComment = getString(body.firstComment) || getString(publishPackage.firstComment) || getString(target.firstComment);
const callbackSecret = getString(callback.secret) || getString($env.SHOWROOM_SHORTS_PUBLISH_CALLBACK_SECRET);

return [{
  json: {
    source: getString(body.source) || 'showroom-shorts',
    action,
    dispatchedAt: getString(body.dispatchedAt) || new Date().toISOString(),
    callbackUrl: getString(callback.url),
    callbackSecretHeaderName: getString(callback.secretHeaderName) || 'x-showroom-shorts-publish-secret',
    callbackSecret,
    jobId: getString(body.jobId) || getString(job.id),
    finalVideoUrl: getString(body.finalVideoUrl) || getString(job.finalVideoUrl),
    sourceVideoUrl: getString(body.sourceVideoUrl) || getString(job.sourceVideoUrl),
    durationSeconds: Number(body.durationSeconds ?? job.durationSeconds ?? 10),
    targetId: getString(body.targetId) || getString(target.id),
    channel,
    title,
    description,
    hashtags: getArray(body.hashtags ?? target.hashtags).map((item) => String(item).trim()).filter(Boolean),
    firstComment,
    publishStatus: getString(body.publishStatus) || getString(target.publishStatus),
    publishPackage,
    preparedTitle: title,
    preparedDescription: getString(publishPackage.descriptionWithHashtags) || description,
    preparedCaption: caption,
    preparedFirstComment: firstComment,
  }
}];

return [{
  json: {
    ...$json,
    callbackBody: {
      targetId: $json.targetId,
      action: 'prepare',
      status: 'launch_ready',
      message: 'upload ready',
      completedAt: new Date().toISOString(),
      payload: {
        title: $json.preparedTitle,
        descriptionWithHashtags: $json.preparedDescription,
        firstComment: $json.preparedFirstComment,
        previewUrl: $json.finalVideoUrl,
        checklist: [
          `${$json.channel} 제목 점검`,
          `${$json.channel} 설명 점검`,
          '최종 MP4 URL 확인',
          '론칭 전 승인 대기'
        ]
      }
    }
  }
}];

return [{
  json: {
    ...$json,
    makePayload: {
      source: 'showroom-shorts',
      action: 'launch',
      targetId: $json.targetId,
      channel: $json.channel,
      jobId: $json.jobId,
      finalVideoUrl: $json.finalVideoUrl,
      title: $json.preparedTitle,
      caption: $json.preparedCaption,
      firstComment: $json.preparedFirstComment,
      callback: {
        url: $json.callbackUrl,
        secretHeaderName: $json.callbackSecretHeaderName,
        secret: $json.callbackSecret,
      }
    }
  }
}];

const normalizeNode = $('입력 정규화').item.json;
return [{
  json: {
    ok: true,
    accepted: true,
    action: 'launch',
    status: 'publishing',
    provider: 'make',
    channel: normalizeNode.channel,
    targetId: normalizeNode.targetId,
    message: 'Make launch accepted'
  }
}];

const normalizeNode = $('입력 정규화').item.json;
const youtubeOutput = $json;
const externalPostId = youtubeOutput.id || `youtube-${Date.now()}`;
const externalPostUrl = youtubeOutput.id ? `https://www.youtube.com/shorts/${youtubeOutput.id}` : `https://www.youtube.com/watch?v=${externalPostId}`;
return [{
  json: {
    ...normalizeNode,
    callbackBody: {
      targetId: normalizeNode.targetId,
      action: 'launch',
      status: 'published',
      message: 'published',
      completedAt: new Date().toISOString(),
      externalPostId,
      externalPostUrl,
      payload: {
        channel: 'youtube',
        finalVideoUrl: normalizeNode.finalVideoUrl,
        youtubeResponse: youtubeOutput
      }
    }
  }
}];

return [{
  json: {
    ...$json,
    callbackBody: {
      targetId: $json.targetId,
      action: 'launch',
      status: 'failed',
      message: `Unsupported channel: ${$json.channel}`,
      payload: {
        channel: $json.channel,
        provider: 'n8n',
        errorCode: 'UNSUPPORTED_CHANNEL'
      }
    }
  }
}];
